const mergeMeta=(meta={})=>{const departments=[...(meta.departments||[])]; rows.value.forEach(i=>{if(i.department&&!departments.includes(i.department)) departments.push(i.department);}); const positions={...(meta.positions||{})}; rows.value.forEach(i=>{if(!i.department||!i.position) return; positions[i.department]=[...new Set([...(positions[i.department]||[]),i.position])].sort();}); org.value={departments:departments.sort(),positions};};
const loadMeta=async()=>{const r=await getEmployeeMeta(); mergeMeta(r.data||{});};
const loadRows=async()=>{loading.value=true;try{const r=await getEmployees();rows.value=(r.data||[]).map(norm); await loadMeta();}finally{loading.value=false;}};
const reset=()=>{eid.value='';Object.assign(f,{...base,employee_no:nextNo(),hire_date:'2026-01-01',probation_end_date:'2026-04-01'});sync();rf.value?.clearValidate();};
const openCreate=()=>{reset();dv.value=true;}; const editRow=row=>{eid.value=row.id;Object.assign(f,{...base,...row});sync();dv.value=true;};
const removeRow=async row=>{await ElMessageBox.confirm(`确认删除员工 ${row.name} 吗？`,'提示',{type:'warning'});await deleteEmployee(row.id);ElMessage.success('删除成功');await loadRows();};
const validFile=(file)=>{const ext=(file.name.split('.').pop()||'').toLowerCase(); if(!['jpg','jpeg','png','pdf'].includes(ext)) return ElMessage.error('附件仅支持 jpg、jpeg、png、pdf'),false; const limit=ext==='pdf'?10*1024*1024:5*1024*1024; if((file.size||0)>limit) return ElMessage.error(ext==='pdf'?'PDF 不能超过 10MB':'图片不能超过 5MB'),false; return true;};
const onUploadChange=async(key,list)=>{const next=[]; for(const item of list){const sourceFile=item.raw||item; if(!validFile(sourceFile)) continue; const encoded=item.raw?await toBase64(item.raw):item.content_base64||''; const mimeType=item.raw?.type||item.mime_type||sourceFile.type||''; next.push({...item,raw:item.raw||sourceFile,mime_type:mimeType,content_base64:encoded,size:sourceFile.size||item.size||0});} u[key]=next; };
const toBase64=(file)=>new Promise((resolve,reject)=>{const reader=new FileReader(); reader.onload=()=>resolve(String(reader.result).split(',')[1]||''); reader.onerror=reject; reader.readAsDataURL(file);});
const previewAttachment=async(field,index)=>{if(eid.value){try{const r=await getEmployeeAttachment(eid.value,field,index); pa.value={...r.data,employee_id:eid.value,field,index}; pv.value=true;}catch(err){if(err?.response?.data?.detail==='附件内容不存在'){ElMessage.warning('该附件是历史数据，未保存文件内容，暂时无法预览'); return;}} return;} const file=u[field][index]; if(!file) return; pa.value={...file,employee_id:eid.value,field,index}; pv.value=true;};
const downloadAttachment=async(field,index)=>{if(eid.value){try{const blob=await downloadEmployeeAttachment(eid.value,field,index); const file=pa.value?.field===field&&pa.value?.index===index?pa.value:u[field][index]; const href=URL.createObjectURL(blob); const link=document.createElement('a'); link.href=href; link.download=file?.name||'附件'; link.click(); setTimeout(()=>URL.revokeObjectURL(href),500);}catch(err){if(err?.response?.status===401){ElMessage.error('请先登录'); return;} if(err?.response?.data?.detail==='附件内容不存在'){ElMessage.warning('该附件是历史数据，未保存文件内容，暂时无法下载'); return;} ElMessage.error('下载失败，请稍后重试');} return;} const file=u[field][index]; if(!file) return; if(file.raw instanceof File){const href=URL.createObjectURL(file.raw); const link=document.createElement('a'); link.href=href; link.download=file.name; link.click(); setTimeout(()=>URL.revokeObjectURL(href),500); return;} if(!file.content_base64) return; const mimeType=file.mime_type||'application/octet-stream'; const binary=atob(file.content_base64); const bytes=new Uint8Array(binary.length); for(let i=0;i<binary.length;i+=1) bytes[i]=binary.charCodeAt(i); const href=URL.createObjectURL(new Blob([bytes],{type:mimeType})); const link=document.createElement('a'); link.href=href; link.download=file.name; link.click(); setTimeout(()=>URL.revokeObjectURL(href),500);};
const downloadPreviewAttachment=()=>{if(pa.value) downloadAttachment(pa.value.field,pa.value.index);};
