const openAiWorkforceReport=async()=>{aiReportLoading.value=true;try{const result=await generateEmployeeWorkforceReport({department:df.value||'',position:pf.value||'',status:sf.value||'',keyword:k.value||''}); aiWorkforceReport.title=result.data?.title||'AI人力结构报表'; aiWorkforceReport.content=result.data?.content||'暂无AI报表结果'; aiReportDialogVisible.value=true;}catch(error){ElMessage.error(error?.response?.data?.detail||'AI 人力结构报表生成失败');}finally{aiReportLoading.value=false;}};
